+	}
+	if len(cfg.Filter.AgentType) != 2 {
+		t.Fatalf("unexpected filter.agent_type: %#v", cfg.Filter.AgentType)
+	}
+	if cfg.Timeout != "30s" {
+		t.Fatalf("unexpected timeout: %q", cfg.Timeout)
+	}
